import java.util.*

fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val baseEdges = mutableListOf<Triple<Int, Int, Long>>()
    for (e in edges) {
        val u = e[0].toInt()
        val v = e[1].toInt()
        val cost = e[2]
        if (online[u] && online[v]) {
            baseEdges.add(Triple(u, v, cost))
        }
    }

    var maxEdge = 0L
    for (triple in baseEdges) {
        if (triple.third > maxEdge) {
            maxEdge = triple.third
        }
    }

    var low = 0L
    var high = maxEdge + 1
    var ans = -1L

    fun check(x: Long): Boolean {
        val adj = Array(n) { mutableListOf<Pair<Int, Long>>() }
        for ((u, v, cost) in baseEdges) {
            if (cost >= x) {
                adj[u].add(v to cost)
            }
        }

        val INF = 1e18.toLong()
        val dist = LongArray(n) { INF }
        val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
        dist[0] = 0
        pq.add(0L to 0)

        while (pq.isNotEmpty()) {
            val (d, u) = pq.poll()
            if (d != dist[u]) continue
            if (u == n - 1) {
                if (d <= k) return true
                return false
            }
            for ((v, w) in adj[u]) {
                val newDist = d + w
                if (newDist > k) continue
                if (newDist < dist[v]) {
                    dist[v] = newDist
                    pq.add(newDist to v)
                }
            }
        }
        return false
    }

    while (low < high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            ans = mid
            low = mid + 1
        } else {
            high = mid
        }
    }

    return ans
}
```

